     2→ * Provider Settings Modal
     3→ * Configure AI provider API keys with encryption
     4→ *
     5→ * Features:
     6→ * - Configure all 8 AI providers (OpenRouter, Groq, HuggingFace, Mistral, Gemini, OpenAI, Anthropic, xAI)
     7→ * - Encrypted API key storage
     8→ * - Visual provider status (configured/unconfigured)
     9→ * - Test API key validation
    10→ * - Provider documentation links
    11→ * - Free vs paid tier indicators
    12→ * - CORS compatibility warnings
    13→ */
    14→
    15→import { useState, useEffect } from 'react';
    16→import { Modal } from './Modal';
    17→import { PasswordPrompt } from './PasswordPrompt';
    18→import { useTerminalStore } from '../stores/useTerminalStore';
    19→import { AIProviderRouter, PROVIDER_METADATA } from '../services/ai/providerRouter';
    20→
    21→interface ProviderSettingsProps {
    22→  isOpen: boolean;
    23→  onClose: () => void;
    24→  router: AIProviderRouter;
    25→}
    26→
    27→export function ProviderSettings({ isOpen, onClose, router }: ProviderSettingsProps) {
    28→  const {
    29→    // providers is unused (using router.getAllProviders() instead)
    30→    encryptionPassword,
    31→    passwordHash,
    32→    isPasswordExpired,
    33→    setProviderApiKey,
    34→    clearProviderApiKey,
    35→    setEncryptionPassword,
    36→    setActiveProvider,
    37→  } = useTerminalStore();
    38→
    39→  const [showPasswordPrompt, setShowPasswordPrompt] = useState(false);
    40→  const [selectedProvider, setSelectedProvider] = useState<string | null>(null);
    41→  const [apiKeyInputs, setApiKeyInputs] = useState<Record<string, string>>({});
    42→  const [showApiKeys, setShowApiKeys] = useState<Record<string, boolean>>({});
    43→  const [validating, setValidating] = useState<Record<string, boolean>>({});
    44→  const [validationResults, setValidationResults] = useState<Record<string, boolean | null>>({});
    45→
    46→  // Get provider metadata (sync - no SDK loading needed for display)
    47→  const providerMetadataList = PROVIDER_METADATA;
    48→  const providerStatus = router.getProviderStatus();
    49→
    50→  // Check if password is needed
    51→  useEffect(() => {
    52→    if (!encryptionPassword || isPasswordExpired()) {
    53→      // Password needed but don't show prompt automatically
    54→      // User will trigger it when trying to save an API key
    55→    }
    56→  }, [encryptionPassword, isPasswordExpired]);
    57→
    58→  const handlePasswordSubmit = (password: string, hash: string, duration: 'daily' | 'weekly' | 'monthly') => {
    59→    setEncryptionPassword(password, hash, duration);
    60→    setShowPasswordPrompt(false);
    61→
    62→    // If user was trying to save a provider, save it now
    63→    if (selectedProvider && apiKeyInputs[selectedProvider]) {
    64→      saveProviderKey(selectedProvider, apiKeyInputs[selectedProvider], password);
    65→    }
    66→  };
    67→
    68→  const saveProviderKey = async (providerId: string, apiKey: string, password: string) => {
    69→    try {
