     1→/**
     2→ * AI Terminal Component
     3→ * Persistent AI assistant with multi-provider chat interface
     4→ *
     5→ * Features:
     6→ * - Multiple AI providers (OpenRouter, Groq, HuggingFace, Mistral, Gemini, OpenAI, Anthropic, xAI)
     7→ * - Provider/model selection
     8→ * - Automatic fallback on errors
     9→ * - Usage tracking
    10→ * - Encrypted API key storage
    11→ */
    12→
    13→import React, { useState, useRef, useEffect, useCallback } from 'react';
    14→import { useTerminalStore } from '../stores/useTerminalStore';
    15→import { aiTerminalService } from '../services/aiTerminal';
    16→import { createDefaultRouter } from '../services/ai/providerRouter';
    17→import { ProviderSettings } from './ProviderSettings';
    18→import { ModelSelector } from './ModelSelector';
    19→import { UsageTracker } from './UsageTracker';
    20→import { TerminalHelpModal } from './TerminalHelpModal';
    21→import { Terminal as PhantomTerminal, Preview as PhantomPreview } from './PhantomShell';
    22→import { usePhantomShellStore } from '../stores/usePhantomShellStore';
    23→import { runCommand, createShellContext, setRouter as setAICommandRouter } from '../services/phantomShell';
    24→import ReactMarkdown from 'react-markdown';
    25→import rehypeSanitize, { defaultSchema } from 'rehype-sanitize';
    26→
    27→type TerminalMode = 'chat' | 'shell';
    28→
    29→/**
    30→ * Custom sanitization schema for AI-generated content
    31→ * Extends default schema to allow safe code elements while blocking dangerous ones
    32→ *
    33→ * Security: This prevents XSS attacks from malicious AI responses
    34→ */
    35→const sanitizeSchema = {
    36→  ...defaultSchema,
    37→  tagNames: [
    38→    // Text formatting
    39→    'p', 'br', 'strong', 'em', 'b', 'i', 'u', 's', 'del', 'ins', 'mark',
    40→    // Headings
    41→    'h1', 'h2', 'h3', 'h4', 'h5', 'h6',
    42→    // Lists
    43→    'ul', 'ol', 'li',
    44→    // Code
    45→    'pre', 'code',
    46→    // Quotes & dividers
    47→    'blockquote', 'hr',
    48→    // Links (href will be sanitized)
    49→    'a',
    50→    // Tables
    51→    'table', 'thead', 'tbody', 'tr', 'th', 'td',
    52→    // Other safe elements
    53→    'span', 'div',
    54→  ],
    55→  attributes: {
    56→    ...defaultSchema.attributes,
    57→    a: ['href', 'title', 'target', 'rel'],
    58→    code: ['className'], // For syntax highlighting classes
    59→    pre: ['className'],
    60→    span: ['className'],
    61→    div: ['className'],
    62→  },
    63→  // Force safe link attributes
    64→  protocols: {
    65→    href: ['http', 'https', 'mailto'],
    66→  },
    67→};
    68→
    69→export const AITerminal: React.FC = () => {
    70→  const {
    71→    isOpen,
    72→    apiKey, // Legacy Gemini key
    73→    // model is legacy and unused - destructured but not assigned to avoid TS error
    74→    activeProvider,
    75→    activeModel,
    76→    providers,
    77→    encryptionPassword,
    78→    isPasswordExpired,
    79→    fallbackEnabled,
    80→    messages,
    81→    isStreaming,
    82→    setOpen,
    83→    setActiveProvider,
    84→    addMessage,
    85→    clearMessages,
    86→    setStreaming,
    87→  } = useTerminalStore();
    88→
    89→  const [input, setInput] = useState('');
    90→  const [streamingContent, setStreamingContent] = useState('');
    91→  const [showProviderSettings, setShowProviderSettings] = useState(false);
    92→  const [showModelSelector, setShowModelSelector] = useState(false);
    93→  const [showUsageTracker, setShowUsageTracker] = useState(false);
    94→  const [showHelpModal, setShowHelpModal] = useState(false);
    95→  const [fallbackNotification, setFallbackNotification] = useState<string | null>(null);
    96→  const [terminalMode, setTerminalMode] = useState<TerminalMode>('chat');
    97→  const [configuredProviderCount, setConfiguredProviderCount] = useState(0);
    98→
    99→  // Phantom Shell state
   100→  const phantomStore = usePhantomShellStore();
   101→  const [shellInput, setShellInput] = useState('');
   102→
   103→  const messagesEndRef = useRef<HTMLDivElement>(null);
   104→  const inputRef = useRef<HTMLTextAreaElement>(null);
   105→  const fallbackTimeoutRef = useRef<NodeJS.Timeout | null>(null);
   106→
   107→  // Initialize provider router
   108→  const [router] = useState(() => createDefaultRouter((failedProvider, _failedModel, nextProvider, nextModel, reason) => {
   109→    // Fallback notification callback
   110→    setFallbackNotification(
   111→      `⚠️ ${failedProvider} failed: ${reason}. Switched to ${nextProvider} (${nextModel}).`
   112→    );
   113→    // Clear any existing timeout to prevent memory leaks
   114→    if (fallbackTimeoutRef.current) {
   115→      clearTimeout(fallbackTimeoutRef.current);
   116→    }
   117→    fallbackTimeoutRef.current = setTimeout(() => setFallbackNotification(null), 5000);
   118→  }));
   119→
   120→  // Share router with AI command service (Phantom Shell)
   121→  useEffect(() => {
   122→    setAICommandRouter(router);
   123→  }, [router]);
   124→
   125→  // Cleanup timeout on unmount
   126→  useEffect(() => {
   127→    return () => {
   128→      if (fallbackTimeoutRef.current) {
   129→        clearTimeout(fallbackTimeoutRef.current);
   130→      }
   131→    };
   132→  }, []);
   133→
   134→  // Auto-scroll to bottom when messages change
   135→  useEffect(() => {
   136→    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
   137→  }, [messages, streamingContent]);
   138→
   139→  // Focus input when terminal opens
   140→  useEffect(() => {
   141→    if (isOpen) {
   142→      inputRef.current?.focus();
   143→    }
   144→  }, [isOpen]);
   145→
   146→  // Initialize AI service with API key (legacy Gemini)
   147→  useEffect(() => {
   148→    if (apiKey) {
   149→      aiTerminalService.setApiKey(apiKey);
   150→    }
   151→  }, [apiKey]);
   152→
   153→  // Configure router with active provider and model
   154→  useEffect(() => {
   155→    router.updateConfig({
   156→      primaryProvider: activeProvider,
   157→      primaryModel: activeModel,
   158→      fallbackEnabled: fallbackEnabled,
   159→    });
   160→  }, [activeProvider, activeModel, fallbackEnabled, router]);
   161→
   162→  // Initialize provider API keys from encrypted storage
   163→  useEffect(() => {
   164→    const initializeApiKeys = async () => {
   165→      if (encryptionPassword && !isPasswordExpired()) {
   166→        const allProviderIds = Object.keys(router.getAllProviderMetadata());
   167→        for (const providerId of allProviderIds) {
   168→          const providerConfig = providers[providerId];
   169→          if (providerConfig && providerConfig.encryptedApiKey) {
   170→            try {
   171→              const decryptedKey = await useTerminalStore.getState().getProviderApiKey(providerId, encryptionPassword);
   172→              if (decryptedKey) {
   173→                // Store key in router - provider SDK will be loaded when needed
   174→                router.setProviderApiKey(providerId, decryptedKey);
   175→              }
   176→            } catch (error) {
   177→              console.error(`Failed to decrypt ${providerId} API key:`, error);
   178→            }
   179→          }
   180→        }
   181→      }
   182→
   183→      // Update configured provider count
   184→      const configuredProviders = await router.getConfiguredProviders();
   185→      setConfiguredProviderCount(configuredProviders.length);
   186→    };
   187→
   188→    initializeApiKeys();
   189→  }, [encryptionPassword, isPasswordExpired, providers, router]);
   190→
   191→  // Keyboard shortcuts
   192→  useEffect(() => {
   193→    const handleKeyDown = (e: KeyboardEvent) => {
   194→      // Cmd/Ctrl + Shift + A to toggle terminal
   195→      if ((e.metaKey || e.ctrlKey) && e.shiftKey && e.key.toLowerCase() === 'a') {
   196→        e.preventDefault();
   197→        setOpen(!isOpen);
   198→      }
   199→    };
   200→
   201→    document.addEventListener('keydown', handleKeyDown);
   202→    return () => document.removeEventListener('keydown', handleKeyDown);
   203→  }, [isOpen, setOpen]);
   204→
   205→  // Phantom Shell: Handle terminal data input
   206→  const handleTerminalData = useCallback((data: string) => {
   207→    // Handle special keys
   208→    if (data === '\r') {
   209→      // Enter key - execute command
   210→      if (shellInput.trim()) {
   211→        const terminal = phantomStore.terminalInstance;
   212→        const context = createShellContext(
   213→          terminal ? { clear: () => terminal.clear(), write: (d: string) => terminal.write(d) } : null,
   214→          {
   215→            activeProjectId: phantomStore.activeProjectId,
   216→            commandHistory: phantomStore.commandHistory,
   217→            projects: phantomStore.projects,
   218→            createProject: phantomStore.createProject,
   219→          }
   220→        );
   221→
   222→        // Add to history
   223→        phantomStore.addToHistory({ command: shellInput });
   224→
   225→        // Execute command
   226→        terminal?.write('\r\n');
   227→        runCommand(shellInput, context, (output) => {
   228→          terminal?.write(output);
   229→        }).then((exitCode) => {
   230→          // Show prompt after command completes
   231→          terminal?.write(`\r\n\x1b[35mphantom\x1b[0m:\x1b[36m~\x1b[0m$ `);
   232→          if (exitCode !== 0) {
   233→            // Exit code shown for non-zero
   234→          }
   235→        });
   236→
   237→        setShellInput('');
   238→      } else {
   239→        // Empty enter - just show new prompt
   240→        phantomStore.terminalInstance?.write('\r\n\x1b[35mphantom\x1b[0m:\x1b[36m~\x1b[0m$ ');
   241→      }
   242→    } else if (data === '\x7f' || data === '\b') {
   243→      // Backspace
   244→      if (shellInput.length > 0) {
   245→        setShellInput(prev => prev.slice(0, -1));
   246→        phantomStore.terminalInstance?.write('\b \b');
   247→      }
   248→    } else if (data === '\x03') {
   249→      // Ctrl+C - cancel current input
   250→      phantomStore.terminalInstance?.write('^C\r\n\x1b[35mphantom\x1b[0m:\x1b[36m~\x1b[0m$ ');
   251→      setShellInput('');
   252→    } else if (data === '\x1b[A') {
   253→      // Up arrow - history navigation
   254→      const prevCmd = phantomStore.navigateHistory('up');
   255→      if (prevCmd !== null) {
   256→        // Clear current line and show previous command
   257→        phantomStore.terminalInstance?.write('\r\x1b[K\x1b[35mphantom\x1b[0m:\x1b[36m~\x1b[0m$ ' + prevCmd);
   258→        setShellInput(prevCmd);
   259→      }
   260→    } else if (data === '\x1b[B') {
   261→      // Down arrow - history navigation
   262→      const nextCmd = phantomStore.navigateHistory('down');
   263→      phantomStore.terminalInstance?.write('\r\x1b[K\x1b[35mphantom\x1b[0m:\x1b[36m~\x1b[0m$ ' + (nextCmd || ''));
   264→      setShellInput(nextCmd || '');
   265→    } else if (data.length === 1 && data >= ' ') {
   266→      // Regular printable character
   267→      setShellInput(prev => prev + data);
   268→      phantomStore.terminalInstance?.write(data);
   269→    }
   270→  }, [shellInput, phantomStore]);
   271→
   272→  // Show prompt when terminal is ready
   273→  const handleTerminalReady = useCallback(() => {
   274→    setTimeout(() => {
   275→      phantomStore.terminalInstance?.write('\x1b[35mphantom\x1b[0m:\x1b[36m~\x1b[0m$ ');
   276→    }, 100);
   277→  }, [phantomStore.terminalInstance]);
   278→
   279→  // Initialize prompt when switching to shell mode
   280→  useEffect(() => {
   281→    if (terminalMode === 'shell' && phantomStore.isTerminalReady) {
   282→      handleTerminalReady();
   283→    }
   284→  }, [terminalMode, phantomStore.isTerminalReady, handleTerminalReady]);
   285→
   286→  const handleSubmit = async (e: React.FormEvent) => {
   287→    e.preventDefault();
   288→    if (!input.trim() || isStreaming) return;
   289→
   290→    const userMessage = input.trim();
   291→    setInput('');
   292→
   293→    // Check if any provider is configured
   294→    if (configuredProviderCount === 0) {
   295→      addMessage({
   296→        role: 'system',
   297→        content: '⚠️ No AI providers configured. Click the ⚙️ Settings button to add API keys.',
   298→      });
   299→      return;
   300→    }
   301→
   302→    // Check if active provider is configured
   303→    const activeProviderObj = await router.getProvider(activeProvider);
   304→    if (!activeProviderObj || !activeProviderObj.isConfigured()) {
   305→      addMessage({
   306→        role: 'system',
   307→        content: `⚠️ Provider "${activeProvider}" is not configured. Please add an API key in Settings.`,
   308→      });
   309→      return;
   310→    }
   311→
   312→    // Add user message
   313→    addMessage({
   314→      role: 'user',
   315→      content: userMessage,
   316→    });
   317→
   318→    // Start streaming
   319→    setStreaming(true);
   320→    setStreamingContent('');
   321→
   322→    try {
   323→      // Send message using router (with automatic fallback)
   324→      const response = await router.sendMessage({
   325→        prompt: userMessage,
   326→        conversationHistory: messages.map((msg) => ({
   327→          role: msg.role as 'user' | 'assistant' | 'system',
   328→          content: msg.content,
   329→        })),
   330→        stream: true,
   331→        onChunk: (chunk) => {
   332→          setStreamingContent((prev) => prev + chunk);
   333→        },
   334→      });
   335→
   336→      // Add complete assistant message with provider/model metadata
   337→      addMessage({
   338→        role: 'assistant',
   339→        content: response.content,
   340→        provider: response.provider || activeProvider,
   341→        model: response.model || activeModel,
   342→      });
   343→    } catch (error) {
   344→      const errorMessage = error instanceof Error ? error.message : 'Unknown error occurred';
   345→      addMessage({
   346→        role: 'system',
   347→        content: `❌ Error: ${errorMessage}`,
   348→      });
   349→    } finally{
   350→      setStreaming(false);
   351→      setStreamingContent('');
   352→    }
   353→  };
   354→
   355→  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
   356→    if (e.key === 'Enter' && !e.shiftKey) {
   357→      e.preventDefault();
   358→      handleSubmit(e);
   359→    }
   360→  };
   361→
   362→  if (!isOpen) return null;
   363→
   364→  return (
   365→    <div
   366→      className={`
   367→        fixed top-0 right-0 h-screen
   368→        transition-transform duration-200 ease-in-out
   369→        ${isOpen ? 'translate-x-0' : 'translate-x-full'}
   370→        w-[300px] lg:w-[375px]
   371→        bg-white dark:bg-black
   372→        border-l border-border-light dark:border-border-dark
   373→        shadow-2xl
   374→        z-40
   375→        flex flex-col
   376→      `}
   377→    >
   378→      {/* Header - Terminal Style */}
   379→      <div className="flex items-center justify-between px-4 py-3 bg-black dark:bg-black text-green-400 border-b border-border-light dark:border-border-dark flex-shrink-0">
   380→        <div className="flex items-center gap-2 font-mono text-sm">
   381→          {/* Mode Toggle Tabs */}
   382→          <div className="flex bg-neutral-900 rounded-button p-0.5 gap-0.5">
   383→            <button
   384→              onClick={() => setTerminalMode('chat')}
   385→              className={`px-2 py-1 text-xs rounded-button transition-all ${
   386→                terminalMode === 'chat'
   387→                  ? 'bg-green-400/20 text-green-400'
   388→                  : 'text-neutral-400 hover:text-green-400'
   389→              }`}
   390→              title="AI Chat Mode"
   391→            >
   392→              💬 Chat
   393→            </button>
   394→            <button
   395→              onClick={() => setTerminalMode('shell')}
   396→              className={`px-2 py-1 text-xs rounded-button transition-all ${
   397→                terminalMode === 'shell'
   398→                  ? 'bg-accent-magenta/20 text-accent-magenta'
   399→                  : 'text-neutral-400 hover:text-accent-magenta'
   400→              }`}
   401→              title="Phantom Shell Terminal"
   402→            >
   403→              ⌨️ Shell
   404→            </button>
   405→          </div>
   406→          {terminalMode === 'chat' && (
   407→            <span className="text-green-400 text-xs">
   408→              {configuredProviderCount > 0
   409→                ? `${activeProvider}/${activeModel}`
   410→                : 'no-provider'}
   411→            </span>
   412→          )}
   413→          {terminalMode === 'shell' && (
   414→            <span className="text-accent-magenta text-xs">phantom-shell</span>
   415→          )}
   416→        </div>
   417→
   418→        <div className="flex items-center gap-1">
   419→          {/* Fallback indicator */}
   420→          {fallbackEnabled && configuredProviderCount > 1 && (
   421→            <span className="text-xs bg-green-400/20 px-2 py-0.5 rounded-button font-mono" title="Automatic fallback enabled">
   422→              🔄
   423→            </span>
   424→          )}
   425→
   426→          {/* Usage Tracker */}
   427→          <button
   428→            onClick={() => setShowUsageTracker(!showUsageTracker)}
   429→            className="p-1 hover:bg-green-400/20 rounded-button transition-all duration-standard ease-smooth text-sm"
   430→            title="Usage Statistics"
   431→            aria-label="View usage statistics"
   432→          >
   433→            📊
   434→          </button>
   435→
   436→          {/* Model Selector */}
   437→          <button
   438→            onClick={() => setShowModelSelector(!showModelSelector)}
   439→            className="p-1 hover:bg-green-400/20 rounded-button transition-all duration-standard ease-smooth text-sm"
   440→            title="Select Model"
   441→            aria-label="Select AI model"
   442→          >
   443→            🔀
   444→          </button>
   445→
   446→          {/* Provider Settings */}
   447→          <button
   448→            onClick={() => setShowProviderSettings(true)}
   449→            className="p-1 hover:bg-green-400/20 rounded-button transition-all duration-standard ease-smooth text-sm"
   450→            title="Provider Settings"
   451→            aria-label="Open provider settings"
   452→          >
   453→            ⚙️
   454→          </button>
   455→
   456→          {/* Help */}
   457→          <button
   458→            onClick={() => setShowHelpModal(true)}
   459→            className="p-1 hover:bg-green-400/20 rounded-button transition-all duration-standard ease-smooth text-sm"
   460→            title="Help & Documentation"
   461→            aria-label="Open help"
   462→          >
   463→            ❓
   464→          </button>
   465→
   466→          {/* Close */}
   467→          <button
   468→            onClick={() => setOpen(false)}
   469→            className="p-1 hover:bg-green-400/20 rounded-button transition-all duration-standard ease-smooth text-base"
   470→            title="Close Terminal"
   471→            aria-label="Close AI terminal"
   472→          >
   473→            ✕
   474→          </button>
   475→        </div>
   476→      </div>
   477→
   478→      {/* Content Area - Chat or Shell */}
   479→      <div className="flex flex-col flex-1 overflow-hidden">
   480→        {/* Phantom Shell Terminal Mode */}
   481→        {terminalMode === 'shell' && (
   482→          <div className="flex flex-col flex-1 overflow-hidden">
   483→            {/* Preview Toggle Bar */}
   484→            <div className="flex items-center justify-between px-2 py-1 bg-neutral-900 border-b border-neutral-800 flex-shrink-0">
   485→              <span className="text-xs text-neutral-500">
   486→                {phantomStore.isDevServerRunning ? '🟢 Server running' : '⚫ No server'}
   487→              </span>
   488→              <button
   489→                onClick={() => phantomStore.setShowPreview(!phantomStore.showPreview)}
   490→                className={`px-2 py-0.5 text-xs rounded transition-all ${
   491→                  phantomStore.showPreview
   492→                    ? 'bg-cyan-500/20 text-cyan-400'
   493→                    : 'text-neutral-500 hover:text-cyan-400'
   494→                }`}
   495→                title="Toggle Preview Pane"
   496→              >
   497→                {phantomStore.showPreview ? '👁 Hide' : '👁 Show'} Preview
   498→              </button>
   499→            </div>
   500→
   501→            {/* Split View: Terminal (top) + Preview (bottom) */}
   502→            <div className="flex flex-col flex-1 overflow-hidden">
   503→              {/* Terminal */}
   504→              <div className={`overflow-hidden transition-all ${
   505→                phantomStore.showPreview ? 'h-[60%]' : 'h-full'
   506→              }`}>
   507→                <PhantomTerminal onData={handleTerminalData} />
   508→              </div>
   509→
   510→              {/* Preview Pane */}
   511→              {phantomStore.showPreview && (
   512→                <div className="h-[40%] border-t border-neutral-800">
   513→                  <PhantomPreview className="w-full h-full" />
   514→                </div>
   515→              )}
   516→            </div>
   517→          </div>
   518→        )}
   519→
   520→        {/* AI Chat Mode */}
   521→        {terminalMode === 'chat' && (
   522→          <>
   523→        {/* Messages */}
   524→        <div className="flex-1 overflow-y-auto p-4 space-y-4">
   525→            {/* Fallback Notification */}
   526→            {fallbackNotification && (
   527→              <div className="mb-4 p-3 bg-yellow-100 dark:bg-yellow-900/30 border border-yellow-400 dark:border-yellow-600 rounded-button text-sm text-text-light-primary dark:text-text-dark-primary">
   528→                {fallbackNotification}
   529→              </div>
   530→            )}
   531→
   532→            {messages.length === 0 && configuredProviderCount === 0 && (
   533→              <div className="text-center py-12 text-text-light-secondary dark:text-text-dark-secondary">
   534→                <p className="text-lg font-semibold mb-2">Welcome to AI Terminal!</p>
