                        onClick={() => handleSaveApiKey(providerId)}
                        disabled={!apiKeyInputs[providerId]?.trim()}
                        className="px-2.5 py-1 bg-accent-blue hover:bg-accent-blue-hover disabled:bg-slate-500/20 disabled:text-slate-500 disabled:cursor-not-allowed text-white rounded-button text-xs transition-all duration-standard ease-smooth"
                      >
                        {isConfigured ? 'Update' : 'Save'}
                      </button>

                      <button
                        onClick={() => handleTestApiKey(providerId)}
                        disabled={!apiKeyInputs[providerId]?.trim() || validating[providerId]}
                        className="px-2.5 py-1 bg-surface-light-elevated dark:bg-surface-dark-elevated hover:bg-surface-light dark:hover:bg-neutral-800 disabled:opacity-50 disabled:cursor-not-allowed border border-border-light dark:border-border-dark rounded-button text-xs text-text-light-primary dark:text-text-dark-primary transition-all duration-standard ease-smooth"
                      >
                        {validating[providerId] ? 'Testing...' : 'Test Key'}
                      </button>

                      {isConfigured && (
                        <button
                          onClick={() => handleClearApiKey(providerId)}
                          className="px-2.5 py-1 bg-red-500/10 hover:bg-red-500/20 border border-red-500/20 rounded-button text-xs text-red-500 transition-all duration-standard ease-smooth"
                        >
                          Remove
                        </button>
                      )}

                      {/* Validation Result */}
                      {validationResults[providerId] !== null && (
                        <span
                          className={`px-1.5 py-1 text-[10px] rounded-button ${
                            validationResults[providerId]
                              ? 'bg-green-500/10 text-green-500'
                              : 'bg-red-500/10 text-red-500'
                          }`}
                        >
                          {validationResults[providerId] ? '✓ Valid' : '✗ Invalid'}
                        </span>
                      )}
                    </div>
                  </div>
                </div>
              );
            })}
          </div>

          {/* Footer Actions */}
          <div className="flex justify-end pt-3 border-t border-border-light dark:border-border-dark">
            <button
              onClick={onClose}
              className="px-3 py-1.5 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-button text-xs transition-all duration-standard ease-smooth"
            >
              Done
            </button>
          </div>
        </div>
      </Modal>

      {/* Password Prompt Modal */}
      <PasswordPrompt
        isOpen={showPasswordPrompt}
        onSubmit={handlePasswordSubmit}
        onCancel={() => {
          setShowPasswordPrompt(false);
          setSelectedProvider(null);
        }}
        mode={passwordHash ? 'unlock' : 'setup'}
        existingPasswordHash={passwordHash || undefined}
      />
    </>
  );
}

