@tailwind base;
@tailwind components;
@tailwind utilities;

/* ==================== CSS DESIGN TOKENS ==================== */
/* These CSS variables power the semantic color system in Tailwind */
/* Source: src/config/theme.ts */

:root {
  /* Surface colors (backgrounds) */
  --surface-light: #FFFFFF;
  --surface-light-elevated: #F3F4F6;
  --surface-dark: #000000;
  --surface-dark-elevated: #1A1A1A;

  /* Text colors */
  --text-light-primary: #000000;
  --text-light-secondary: #6B7280;
  --text-light-tertiary: #9CA3AF;
  --text-dark-primary: #FFFFFF;
  --text-dark-secondary: #D1D5DB;
  --text-dark-tertiary: #6B7280;

  /* Border colors */
  --border-light: #E2E8F0;
  --border-dark: rgba(255, 255, 255, 0.1);

  /* Accent colors (from logo: magenta, cyan) */
  --accent-blue: #3B82F6;
  --accent-blue-hover: #2563EB;
  --accent-magenta: #E91E8C;
  --accent-magenta-hover: #D11A7C;
  --accent-cyan: #00C9FF;
  --accent-cyan-hover: #00B3E6;

  /* Extended accent colors (for status indicators, tags, features) */
  --accent-green: #10B981;
  --accent-green-hover: #059669;
  --accent-purple: #A855F7;
  --accent-purple-hover: #9333EA;
  --accent-red: #EF4444;
  --accent-red-hover: #DC2626;
  --accent-yellow: #F59E0B;
  --accent-yellow-hover: #D97706;
  --accent-orange: #F97316;
  --accent-orange-hover: #EA580C;

  /* Status colors (aliases for semantic use) */
  --status-success: #10B981;
  --status-warning: #F59E0B;
  --status-error: #EF4444;
  --status-info: #3B82F6;
}

@layer base {
  html, body {
    overflow-x: hidden; /* Prevent horizontal scrollbar at root level */
  }

  body {
    margin: 0;
    min-height: 100vh;
    font-family: 'Inter', system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    font-size: 16px; /* Increased from 14px for better readability */
    line-height: 1.5; /* Professional line-height */
    @apply bg-surface-light dark:bg-surface-dark;
    @apply text-text-light-primary dark:text-text-dark-primary;
  }

  /* Professional Typography Hierarchy */
  h1 {
    font-size: 32px;
    font-weight: 700;
    line-height: 1.2;
    letter-spacing: -0.02em;
  }

  h2 {
    font-size: 24px;
    font-weight: 700;
    line-height: 1.3;
    letter-spacing: -0.01em;
  }

  h3 {
    font-size: 20px;
    font-weight: 600;
    line-height: 1.4;
  }

  h4 {
    font-size: 18px;
    font-weight: 600;
    line-height: 1.4;
  }

  h5, h6 {
    font-size: 16px;
    font-weight: 600;
    line-height: 1.5;

